const body = $input.first().json.body || $input.first().json;

const required = ['clinic_name', 'city'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Champ obligatoire manquant : ${field}`);
  }
}

return [{
  json: {
    clinic_name: body.clinic_name || '',
    city: body.city || '',
    website_url: body.website_url || 'non renseigné',
    gmaps_url: body.gmaps_url || 'non renseigné',
    google_reviews_count: body.google_reviews_count || 0,
    google_rating: body.google_rating || 0,
    instagram_url: body.instagram_url || 'non renseigné',
    meta_ads_active: body.meta_ads_active || 'non',
    services_description: body.services_description || 'non renseigné',
    contact_email: body.contact_email || 'non renseigné',
    phone: body.phone || 'non renseigné',
    notes: body.notes || ''
  }
}];

