const raw = $input.first().json.choices?.[0]?.message?.content || $input.first().json.text || '';

let result;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Réponse IA invalide (JSON non parsable) : ${raw}`);
}

const required = ['nom', 'score', 'segment', 'raisons', 'priorite_contact'];
for (const field of required) {
  if (result[field] === undefined || result[field] === null) {
    throw new Error(`Champ manquant dans la réponse QUALIFIER : ${field}`);
  }
}

if (typeof result.score !== 'number' || result.score < 0 || result.score > 100) {
  throw new Error(`Score invalide : ${result.score}. Doit être un entier entre 0 et 100.`);
}

if (!['HOT', 'WARM', 'COLD'].includes(result.segment)) {
  throw new Error(`Segment invalide : ${result.segment}. Doit être HOT, WARM ou COLD.`);
}

if (!['haute', 'moyenne', 'basse'].includes(result.priorite_contact)) {
  throw new Error(`priorite_contact invalide : ${result.priorite_contact}.`);
}

if (!Array.isArray(result.raisons) || result.raisons.length < 1) {
  throw new Error('raisons doit être un tableau non vide.');
}

const segmentMap = { HOT: 'haute', WARM: 'moyenne', COLD: 'basse' };
if (segmentMap[result.segment] !== result.priorite_contact) {
  throw new Error(`Incohérence : segment ${result.segment} doit avoir priorite_contact "${segmentMap[result.segment]}" mais reçu "${result.priorite_contact}".`);
}

result.scored_at = new Date().toISOString();

return [{ json: result }];
